#include <bits/stdc++.h>
using namespace std;

int main(){
    int n;
    cin >> n;
    vector<pair<int, int>> doctors;
    for(int i = 0; i < n; i++){
        int s, d;
        cin >> s >> d;
        doctors.push_back({s, d});
    }
    int ans = 0;
    for(int i = 0; i < n; i++){
        int s = doctors[i].first;
        int d = doctors[i].second;
        if(ans < s){
            ans = s;
        }
        while(s <= ans){
            s += d;
        }
        ans = s;
    }
    cout << ans << endl;
    return 0;
}
